      "content": "const express = require('express');
const app = express();
const port = 3000;

// Middleware to parse JSON bodies
app.use(express.json());

// Import routes
const projectsRoutes = require('./modules/projects/routes').router;
const membersRoutes = require('./modules/members/routes').router;
const tasksRoutes = require('./modules/tasks/routes').router;
const commentsRoutes = require('./modules/comments/routes').router;

// Mount routes
app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

// Start the server
const server = app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});"
